var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>2049년 12월 24일</color>","JPN":"<color=#ffd34c>2049年12月24日</color>","ENG":"<color=#ffd34c>December 24, 2049</color>","TWN":"<color=#ffd34c>2049年12月24日</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임, 진행 중</color>","JPN":"<color=#ffd34c>クリフォトゲーム進行中</color>","ENG":"<color=#ffd34c>Qliphoth Game in progress</color>","TWN":"<color=#ffd34c>逆卡巴拉遊戲，進行中</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"작전 시작 전에 브리핑 하겠습니다.","JPN":"作戦開始に先んじてブリーフィングを行います。","ENG":"We'll begin the briefing before the operation starts.","TWN":"作戰開始前進行任務說明。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이번 작전의 최우선 목표는 보름 전에 점령당한 합중국의 B17 연구 시설…….","JPN":"今回の作戦の最優先目標は、2週間前に占領された合衆国のB17研究施設……","ENG":"The main target of this operation is the B17 research facility in the States, which was overtaken 2 weeks ago...","TWN":"此次作戰的首要目標是半個月前被佔領的合眾國B17研究設施……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이곳에 보관된 고등급 아티팩트를 회수하는 것입니다.","JPN":"そこに保管されている高ランクのアーティファクトを回収すること。","ENG":"The objective is to retrieve a high-grade Artifact stored at this location.","TWN":"回收保存在此處的高級神器。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"보름 전에 점령당한 연구소라면, 4종 침식체가 출몰한 곳 말입니까?","JPN":"2週間前に占領された研究所なら、第4種侵食体が出たあの場所ではありませんか？","ENG":"Wait, the lab that was overrun two weeks ago? The one where a Category 4 C.O. appeared?","TWN":"你是說半個月前被佔領的研究所，是出現了4類侵蝕體的地方嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"무리입니다! 카운터가 포함된 부대라고 해도, 최소한 중대급 이상의 병력이 필요합니다!","JPN":"無理です！　いくらカウンターのいる部隊とはいえ、少なくとも中隊級以上の兵力が必要です！","ENG":"This is impossible! Even with a unit that includes Counters, we'll need at least a company-sized force!","TWN":"不行！即使是包含制裁者的部隊，至少也需要中隊級以上的兵力！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"겨우 이 정도 병력으로는…….","JPN":"たったこれだけの兵力では……","ENG":"With just this small a team... there's no way...","TWN":"僅憑這點兵力……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"병력이 부족한 건 사실입니다.","JPN":"兵力が足りていないのは事実です。","ENG":"We are indeed short on manpower.","TWN":"兵力不足是事實。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이번 작전은 대령님께서 양동 작전을 펼쳐 주시기로 하셨습니다.","JPN":"しかし今回の作戦は大佐自ら、陽動作戦に参加されます。","ENG":"However, the Colonel has agreed to carry out a diversionary operation.","TWN":"但是這次作戰是由上校你來展開佯攻作戰的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님께서 시설을 점거하고 있는 4종 침식체를 상대하는 동안, 우리 작전조가 시설에 침투.","JPN":"大佐が施設を占拠している第4種侵食体を相手されている間、我々作戦組が施設へ侵入。","ENG":"While the Colonel keeps the Category 4 C.O. holding the facility occupied, our squad will infiltrate.","TWN":"在上校對抗佔據設施的4類侵蝕體時，我們的作戰小組將潛入設施。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"목표 아티팩트를 회수합니다.","JPN":"ターゲットであるアーティファクトを回収します。","ENG":"And then we will retrieve the Artifact.","TWN":"回收目標人造神器。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"워커 대령님께서요……?","JPN":"ウォーカー大佐が……？","ENG":"Colonel Walker...?","TWN":"沃克上校……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"지난 사도와의 전투에서 큰 부상을 입으셨다고 들었는데…….","JPN":"先日の使徒との戦闘で重傷を負われたと聞きましたが……","ENG":"But I heard he was seriously injured in the last battle against the Apostle...","TWN":"聽說你在上次與使徒的戰鬥中受了重傷……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……그렇습니다.","JPN":"……そうです。","ENG":"...That's correct.","TWN":"……是的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다시 말해, 그만큼 중요한 작전이라는 뜻입니다.","JPN":"つまり、それほど重要な作戦ということです。","ENG":"In other words, that's how critical this operation is.","TWN":"換句話說，這意味著這次作戰非常重要。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니 반드시… 작전을 성공시켜야만 합니다.","JPN":"ですから必ず……作戦を成功させなければなりません。","ENG":"Which means... we must see it through to success.","TWN":"所以一定要……成功完成作戰任務。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"보고에 따르면, 연구 시설의 동력원이 살아있다고 합니다.","JPN":"報告によると、研究施設の動力源はまだ生きています。","ENG":"According to reports, the facility's power source is still operational.","TWN":"報告稱，研究設施的動力源還在運作。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"따라서 작전조는 시설에 도착하면, 최우선적으로 컨트롤 룸을 확보.","JPN":"したがって、作戦組は施設に到着し次第、最優先でコントロールルームを確保。","ENG":"Upon arrival, the squad will prioritize securing the control room.","TWN":"因此，作戰小組到達設施後，首先要確保控制室的安全。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨가 신속하게 데이터베이스에 접근하여, 아티팩트의 위치를 탐색해주세요.","JPN":"その後、シルビアさんは速やかにデータベースにアクセスし、アーティファクトの位置を探ってください。","ENG":"Sylvia, you'll access the database immediately and locate the Artifact.","TWN":"希爾維亞，請迅速訪問資料庫，搜索神器的位置。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"쳇, 어쩐지 현장 타입도 아닌 나를 왜 끌고 왔나 했더니…….","JPN":"ちっ、現場向きでもないアタシを引っ張り出してきた理由はそれだったのね……","ENG":"Tch... I had a feeling. I was wondering why they needed someone like me out in the field...","TWN":"嘖，難怪把我這個非現場類型的人也帶來了……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서? 그 잘난 아티팩트가 뭐길래, 이 난리법석을 치르는 거야?","JPN":"で？　そこまでして取り返したいそのアーティファクトはいったい何なの。","ENG":"So? What's so special about this Artifact that it's worth all this chaos?","TWN":"所以呢？那個了不起的人造神器到底是什麼，竟然鬧得這麼沸沸揚揚？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"모릅니다.","JPN":"わかりません。","ENG":"We don't know.","TWN":"不知道。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"わからないですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>자체적으로 발광하는 보석 형태의 아티팩트…….</color>","JPN":"<color=#ffd34c>発光する宝石型のアーティファクト……</color>","ENG":"<color=#ffd34c>It's a gem-like Artifact that emits light on its own...</color>","TWN":"<color=#ffd34c>自發光寶石形態的神器……</color>"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 이외의 정보는 전부 1급 기밀사항이라, 저도 전달받지 못했습니다.","JPN":"それ以外の情報は全て第1級の機密事項である故、僕も聞かされていません。","ENG":"All other details are classified as top secret, so I haven't been briefed either.","TWN":"除此之外的所有資訊都是一級機密，我也沒有被告知。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 지금 장난해?","JPN":"ちょっと、ふざけてるの？","ENG":"Are you kidding me right now?","TWN":"你覺得現在是開玩笑的時候嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 빌어먹을 군바리 자식! 뭘 찾는지는 알려줘야 찾든 말든 할 거 아니야?","JPN":"あのクソ軍人！　知りもしないものをどうやって探すのよ！？","ENG":"That damn GI! How are we supposed to find something if we don't even know what we're looking for?!","TWN":"該死的軍人！你總得告訴我找什麼，我才能決定找不找吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"발언을 삼가세요, 실비아 씨.","JPN":"言葉を慎んでください、シルビアさん。","ENG":"Watch your words, Sylvia.","TWN":"請注意言辭，希爾維亞。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"부사령관님께서는 데이터베이스에 접촉하면, 곧바로 목표를 파악할 수 있다고 하셨습니다.","JPN":"副司令官はデータベースにアクセスすれば、すぐにターゲットの把握が可能だと仰いました。","ENG":"The Deputy Commander stated that once we access the database, the objective will be immediately identifiable.","TWN":"副司令官說只要接觸資料庫，就能立即掌握目標。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"곧바로? 곧바로 모르면 어쩔 건데?","JPN":"すぐに？　すぐにわからなかったらどうすんの。","ENG":"Immediately? And what if we don't figure it out immediately?","TWN":"馬上？要是馬上知道不了怎麼辦？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"인류의 미래가 걸린 중요한 작전이라면서? 그깟 기밀이 뭐라고 설명을 안해주는 건데!","JPN":"人類の未来がかかった大事な作戦なんでしょ？　何が機密よ！","ENG":"Isn't this supposed to be an operation that decides humanity's future? But we can't even get a proper explanation because of some ridiculous confidentiality?!","TWN":"說是關乎人類未來的重要作戰對吧？那點機密有什麼不能解釋的！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지휘부에서 곧바로 알 수 있다면, 곧바로 알 수 있는 겁니다.","JPN":"司令部がすぐにわかると判断したのなら、わかるはずです。","ENG":"If headquarters says it can be identified immediately, then it can be identified immediately.","TWN":"如果指揮部能馬上知道，那就是馬上知道。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 아니라면, 지금 항명이라도 하시겠다는 겁니까?","JPN":"それとも、命令に歯向かうおつもりですか？","ENG":"Unless, of course, you're planning to defy orders right now.","TWN":"如果不是那樣的話，你是打算現在就抗命嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야! 너, 말 다했어? 지금 한 번 해보자는 거야?","JPN":"なんですって！？　喧嘩売ろうっての？","ENG":"What did you just say? You wanna settle this right now?!","TWN":"喂！你，說完了沒有？你是想比劃比劃嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"아하하… 저기 미안한데 말이야……?","JPN":"あはは……お取込み中に申し訳ないんだけど……","ENG":"Ahaha... sorry to cut in, but...","TWN":"啊哈哈……那個，對不起……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"사이좋게 꽁냥거리는 건, 둘만 있을 때 해주면 안 될까?","JPN":"イチャつくのは、2人きりの時にしてもらえるかな？","ENG":"Mind saving the couples' quarrel for later?","TWN":"能不能等只有你們兩個人的時候，再卿卿我我呢？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"좁아터진 장갑차에 부대껴서 서라운드로 땍땍거리니까, 안 하던 멀미가 올라와서 말이야.","JPN":"ただでさえ狭い装甲車に詰められた上に、両側から騒がれると、酔いそうになるんだよね。","ENG":"All this echoing tension in an armored vehicle is making me feel motion sick.","TWN":"擠在狹窄的裝甲車裡，四周都是嘰嘰喳喳的聲音，搞得我都開始暈車了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_QM","text":{"KOREA":"피차 이게 마지막이 될 수도 있다면서? 엔간하면 좋게 좋게 가자고?","JPN":"お互いこれが最後かもしれないんじゃん？　仲良く行こうよ。","ENG":"Come on, we all know this might be our final operation. Can we not go out bickering like kids?","TWN":"說不定這就是最後一次了？儘量好好相處吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"누가 꽁냥거렸다는 겁니까! 말 조심하세요, 에이미 스트릭랜드.","JPN":"イチャついてなどいません！　発言には注意してください、エイミー・ストリクランド。","ENG":"Couples' quarrel? Watch your mouth, Amy Strickland!","TWN":"誰在打情罵俏啊！說話小心點，艾米·斯特里克蘭。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"카운터 총동원령에 의해 징집된 이상, 당신 역시 더는 민간인이 아니라 군인 신분입니다.","JPN":"カウンター総動員令により招集されたからには、あなたももう民間人ではなく軍人の身分です。","ENG":"You were drafted under the Counter mobilization order. That means you're no longer a civilian. You're a soldier.","TWN":"根據制裁者總動員令被徵召後，你已經不再是平民，而是軍人。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 저는 이 작전에 지휘관이자, 당신 상관이고요.","JPN":"そして僕はこの作戦の指揮官であり、あなたの上官でもあります。","ENG":"And in this operation, I'm the commander, which makes me your superior.","TWN":"還有，我是這次作戰的指揮官，也是你的上司。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아하하, 그래? 근데 이거 어쩌나?","JPN":"あはは、そう？　でも残念。","ENG":"Ahaha, is that so? Well, that's a problem.","TWN":"啊哈哈，是嗎？不過這可怎麼辦呢？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"나는 누구 밑에서 뒤치다꺼리나 해주는 건, 딱 질색이거든~?","JPN":"エイミーは誰かの下に付いて尻拭いなんて、まっぴらごめんだからさ～","ENG":"Taking orders and cleaning up after someone? Not my style.","TWN":"我最討厭在別人手下做雜事了～"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"今なんと？","ENG":"Excuse me?","TWN":"你說什麼？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그보다 슬슬 준비하는 게 좋을 걸? 아까부터 침식파 때문에 피부가 따끔따끔하잖아?","JPN":"それより、そろそろ準備した方がいいよ？　さっきから侵食波のせいで肌がちくちくするし～？","ENG":"Anyway, you might want to start getting ready. I've been feeling Corruption rays prickling my skin for a while now.","TWN":"比起這個，還是趕緊準備吧？從剛才開始就因為侵蝕波皮膚一直刺痛呢！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌면 벌써 녀석들의 영역에 돌입했을지도 모르지.","JPN":"ひょっとしたらもうあいつらの縄張りに入ってるのかも。","ENG":"We might've already stepped into their territory.","TWN":"說不定已經進入了那些傢伙的領地。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_NULL","text":{"KOREA":"소령님! 전방에 침식 쐐기 3기가 나타났습니다!","JPN":"少佐！　前方に侵食楔、3機出現しました！","ENG":"Major! Three Corrupted Wedges just appeared up ahead!","TWN":"少校先生！前方出現了3個侵蝕釘！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아하하! 하여간 말 끝나기가 무섭다니까~","JPN":"あはは！　言わんこっちゃない～","ENG":"Haha! Seriously, the moment I open my mouth, something happens!","TWN":"啊哈哈！總是話還沒說完就急著結束～"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어쩔 거야, 소령님? 여기서 발목 잡혔다간, 양동이고 나발이고 다들 줄초상 치르게 될걸?","JPN":"どうする、少佐？　ここでもたもたしてたら陽動も何も、全員地獄行きだよ？","ENG":"What's the plan, Major? If we get bogged down here, forget the diversion. Everyone's walking into a massacre.","TWN":"怎麼辦，少校先生？如果在這裡被拖住的話，不管是採用佯攻還是其他方案，大家都會全軍覆沒的！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"쳇, 명령은 이쪽에서 합니다. 전원 전투 준비……!","JPN":"ちっ、命令はこちらが出します。総員、戦闘準備……！","ENG":"Tch. I'm the one giving orders here. All units, prepare for combat...!","TWN":"嘖，命令由我來下。全員準備戰鬥……！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"후우……!","JPN":"ふう……！","ENG":"*Sigh…!*","TWN":"呼……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이걸로 어찌저찌 한 건 해결인가?","JPN":"これでなんとか一件落着かな？","ENG":"Guess that's one issue wrapped up, more or less?","TWN":"用這個就能解決問題了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"음? 뭘 그렇게 빤히 쳐다봐?","JPN":"ん？　エイミーの顔に何かついてる？","ENG":"Hmm? What are you staring at?","TWN":"嗯？你為什麼那樣盯著我看？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"설마 나한테 반하기라도 한 거야? 난 댁같이 샌님 같은 스타일은 별론데?","JPN":"まさかエイミーに惚れたとか？　悪いけど、エイミーはおたくみたいな堅物はあんま好みじゃないんだよね。","ENG":"Wait, don't tell me you've got a crush? Hate to break it to you, but nerdy types just don't do it for me.","TWN":"難道你對我動心了嗎？我可不喜歡你這種書呆子類型的喔？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"시끄럽습니다, 스트릭랜드.","JPN":"黙ってください、ストリクランド。","ENG":"Silence, Strickland.","TWN":"閉嘴，斯特里克蘭。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"총동원령에 의해 강제 징집된 C급 카운터치고 제법 움직임이 빠르다고 생각했을 뿐입니다.","JPN":"総動員令により強制招集されたC級カウンターにしては、動きが素早いと思っただけです。","ENG":"I merely noted that, for a Grade C Counter drafted under the mobilization order, your reaction speed is surprisingly adequate.","TWN":"只是覺得被總動員令強制徵召的C級制裁者動作還算迅速。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"헤에~ 소령님은 칭찬을 이상하게 하는 버릇이 있구나~?","JPN":"へぇ～、少佐の褒め方って素直じゃないね～？","ENG":"Wow! Is that how you compliment people, Major?","TWN":"嘿～看來少校你有個奇怪的習慣，喜歡誇人？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일, 들리나?","JPN":"カイル、聞こえるか？","ENG":"Kyle, do you copy?","TWN":"凱爾，能聽到嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네, 말씀하십시오. 대령님.","JPN":"はい、聞いています。大佐。","ENG":"Yes, go ahead, Colonel.","TWN":"可以，上校請說。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이쪽에서 육안으로 시설을 점거하고 있는 4종 침식체를 확인했다.","JPN":"こちらから肉眼で施設を占拠している第4種侵食体を確認した。","ENG":"I've visually confirmed a Category 4 C.O. occupying the facility.","TWN":"這邊用肉眼確認了佔據設施的4類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"예정대로 5분 뒤에 녀석을 끌어내겠다. 그 사이 시설에 돌입. 아티팩트를 회수하도록.","JPN":"予定どおり5分後、奴をおびき出す。その隙に施設に突入し、アーティファクトを回収するように。","ENG":"I'll lure it out in five minutes, just as planned. You breach the facility and secure the Artifact.","TWN":"按照計畫，5分鐘後將它拖出來。在此期間進入設施，回收神器。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대령님…….","JPN":"大佐……","ENG":"Colonel...","TWN":"上校……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"정말 괜찮으시겠습니까? 상대는 4종 침식체입니다. 국가 단위의 재앙이라고요.","JPN":"本当に行かれるのですか？　相手は第4種侵食体。国家単位の脅威です。","ENG":"Are you sure about this? We're talking about a Category 4 C.O., something that could wipe out a whole nation.","TWN":"真的沒問題嗎？對方可是四類侵蝕體啊，這可是國家級的災難啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하! 뭐야, 지금 내 걱정을 해주는 거냐? 이거 영광인걸?","JPN":"はは！　なんだ、心配してくれてるのか？　こりゃ光栄だな。","ENG":"Haha! You're actually worried about me? I'm honored!","TWN":"哈哈！怎麼，現在是在擔心我嗎？這可是我的榮幸啊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이봐, 카일. 걱정하지 말고, 네 작전에만 집중해.","JPN":"おい、カイル。余計な心配はせず、お前に与えられた作戦に集中しろ。","ENG":"Listen, Kyle. Don't worry about me. Just focus on your part of the operation.","TWN":"喂，凱爾，別擔心，專注於你的作戰計畫。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어차피 클리포트 게임에서 우리의 역할은 결국 그 정도뿐이니까.","JPN":"どうせクリフォトゲームでの俺らの役割は、その程度に過ぎないんだ。","ENG":"In the Qliphoth Game, that's all the role we've been given anyway.","TWN":"反正我們在逆卡巴拉遊戲中的角色也就那樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 대령님.","JPN":"承知しました。","ENG":"Understood, Colonel.","TWN":"明白，上校。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……시설 보안 시스템 권한 탈취 성공.","JPN":"……施設セキュリティーシステム権限奪取成功。","ENG":"...Facility security system authority stolen successfully.","TWN":"……成功奪取設施安全系統許可權。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"운이 좋네. 컨트롤 룸 상태가 이 지경인데, 비상 동력원이 아직까지 살아있다니…….","JPN":"運がよかったわね。コントロールルームがこんな有様なのに、非常動力源がまだ生きてるなんて……","ENG":"We're lucky. Even with the control room in this state, the emergency power's still running...","TWN":"運氣真好，控制室的狀態已經這麼糟糕了，緊急電源竟然還在運作……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 시설은 관리국과 합중국이 공조하여 어떤 프로젝트를 수행했던 시설이라고 들었습니다.","JPN":"この施設は管理局と合衆国が共同で、あるプロジェクトを行った施設と聞きました。","ENG":"I heard this facility was used for a joint project between the Administration and the States.","TWN":"聽說這個設施是管理局和合眾國共同執行某個項目的設施。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어쩌면 중요 아티팩트의 기능 유지를 위해, 이런 설비를 갖추고 있는 걸지도 모르죠.","JPN":"もしかすると、重要なアーティファクトの機能維持のために、このような設備を備えているのかも知れません。","ENG":"They might've installed these systems to ensure a critical Artifact remained stable.","TWN":"或許是為了維持重要神器的功能，才配備了這樣的設備吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"흐음~ 여긴 죄다 박살 나서 재밌어 보이는 게 하나도 없는데~","JPN":"ふーん、でも今はご覧の通り、全部壊れちゃってるよ。もうつまんないな～","ENG":"Hmm... this place is totally wrecked. Not a single thing worth checking out!","TWN":"嗯～ 這裡全都被毀了，一點意思都沒有～"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요, 스트릭랜드.","JPN":"言ったはずです、ストリクランド。","ENG":"Strickland, I believe I made myself clear.","TWN":"我應該說過，斯特里克蘭。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"우린 여기 놀러 온 게 아닙니다. 다음 지시가 있을 때까지 얌전히 대기하세요.","JPN":"僕たちはここに遊びに来たわけではありません。次の指示まで、大人しく待機してください。","ENG":"This isn't a field trip. Remain in position and wait for the next orders.","TWN":"我們不是來這裡玩的。在接到下一步指示之前，請安靜等待。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"글쎄? 내가 제일 못하는 게 얌전히 기다리는 거거든?","JPN":"できるかな？　それ、エイミーが一番苦手なやつなんだわ。","ENG":"Remaining in position and waiting? Yeah, not exactly my strong suit.","TWN":"這個嘛？我最不擅長的就是乖乖等待了？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그래서 해커, 그 한눈에 알 수 있다는 고등급 아티팩트는 어디 있다는 건데?","JPN":"それで？　ハッカーさん、その一目でわかるらしい高ランクのアーティファクトはどこにあるの？","ENG":"Hacker, so where's that high-grade Artifact we were supposedly gonna identify immediately?","TWN":"所以駭客，那件一眼就能認出的高級神器在哪裡？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"기다려 봐, 지금 시설 데이터베이스에 접근하고 있으니까.","JPN":"待ってなさい、今施設のデータベースにアクセスしてるから。","ENG":"Hold on, I'm accessing the facility database right now.","TWN":"等一下，我正在訪問設施資料庫。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아티팩트의 별칭이나, 연구 코드를 알고 있다면 조금 더 빠르게 특정할 수 있겠지만.","JPN":"アーティファクトの別名とか研究コードがわかれば、もっと早く特定できるんだろうけど。","ENG":"If we had the Artifact's alias or research code, I could pinpoint it a lot faster...","TWN":"如果知道神器的別名或研究代碼的話，或許能更快地確定。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 잘나신 기밀인지, 뭔지 때문에 우리가 가진 정보는 매우 한정적이라고.","JPN":"機密だかなんだかのせいで、こっちが持ってる情報はとにかく限定的なのよ。","ENG":"But thanks to all that \\"classified\\" nonsense, the data we have is extremely limited.","TWN":"就因為那些所謂的機密，我們掌握的資訊非常有限。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"게다가 곧바로 알 수 있다는 게 무슨 뜻인지…….","JPN":"それにすぐにわかるってどういうこと……","ENG":"And what does \\"immediately identifiable\\" even mean, anyway?","TWN":"一眼就能認出來是什麼意思……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"오호라, 이거 신기하네.","JPN":"へぇ、これ不思議～","ENG":"Well, well, this is interesting.","TWN":"喔吼，這個真有意思。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"여기 리스트가 전부 이 시설에서 보관하고 있는 아티팩트란 말이지?","JPN":"ここのリストが全部、この施設で保管してるアーティファクトってことでしょ？","ENG":"So this list shows all the Artifacts stored in this facility, huh?","TWN":"這裡的清單全都是這個設施裡保存的人造神器嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어차피 폐기된 시설이니까, 한 두개쯤 슬쩍 사라져도 아무도 모르지 않을까?","JPN":"どうせ廃棄された施設なんだし、1個や2個くすねたところでバレないんじゃないかな？","ENG":"I mean, it's an abandoned facility anyway, so who's gonna notice if one or two things go missing, right?","TWN":"反正是廢棄的設施，消失一兩個也沒人會知道吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"글쎄? 함부로 손대지 않는 게 좋을 걸?","JPN":"さあね？　下手に触らない方がいいわよ？","ENG":"Careful. It's better not to touch anything recklessly.","TWN":"哼哼？最好不要輕舉妄動喔？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아티팩트 중에서는 특정 파장을 방출해서 침식체를 유도하는 성질을 가진 물건도 있거든.","JPN":"アーティファクトの中には、特定の波長を放って侵食体をおびき寄せる性質を持ってるものも多いから。","ENG":"Some Artifacts emit specific wavelengths that can attract C.O.s.","TWN":"有些人造神器會釋放特定波長，從而引導侵蝕體。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 효과가 검증되지 않은 아티팩트는 애초부터 만지지도 않는 게……","JPN":"だから効果が検証されていないアーティファクトは、そもそも触らない方が……","ENG":"So if the Artifact hasn't been verified, don't even think about laying a finger on it...","TWN":"所以說，效果未經驗證的神器，最好一開始就不要碰……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐!?","JPN":"待って！？","ENG":"Wait!","TWN":"等等？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……이런 미친!","JPN":"……あんのクソ！","ENG":"...This is insane!","TWN":"……這瘋子！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨, 뭔가 알아냈습니까?","JPN":"シルビアさん、何かわかりましたか？","ENG":"Sylvia, did you find something?","TWN":"希爾維亞，有什麼發現嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알아내? 그야 알아내기야 했지……!","JPN":"わかる？　ええ、わかったわ……！","ENG":"Find something? Oh, I found something, all right...!","TWN":"知道什麼了嗎？當然知道了……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 미친 군바리 자식이 우릴 다 죽일 생각이었다는 걸 말이야!","JPN":"あのイカレた軍人が、アタシたちを全員殺すつもりだったってことがね！","ENG":"That damn GI planned to get us all killed, that's what!","TWN":"那個瘋子竟然想要殺了我們所有人！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 무슨 소리입니까?","JPN":"どういうことですか？","ENG":"What are you talking about?","TWN":"那是什麼意思？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우리가 찾아야 하는 게 자체적으로 발광하는 보석 형태의 아티팩트라면서?","JPN":"アタシたちが探すアーティファクトって、宝石型で、発光してるって言ったわよね？","ENG":"Weren't we told that we're looking for a gem-like Artifact that emits light on its own?","TWN":"我們要找的是一種會自發光的，寶石形態的神器，對吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아티팩트가 발광한다는 건… 다시 말해, 어떤 파장을 계속해서 방출하고 있다는 뜻이야.","JPN":"アーティファクトが発光するってことは……つまり、ある波長を放ち続けているということ。","ENG":"If it's emitting light on its own... that means it's constantly radiating some kind of wavelength.","TWN":"神器發光的意思是……換句話說，就是在不斷釋放某種波長。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 이 시설에서 가장 강력한 파장을 방출하고 있는 아티팩트는… 바로 이거야……!","JPN":"そしてこの施設で最も強い波長を放ち続けているアーティファクトは、これしかない……！","ENG":"And the Artifact emitting the strongest wavelength in this entire facility... is this one...!","TWN":"而在這個設施中釋放出最強烈波動的神器就是……這個……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>불멸체 코어</color>?","JPN":"<color=#ffd34c>不滅体コア</color>？","ENG":"<color=#ffd34c>Immortal System Core</color>?","TWN":"<color=#ffd34c>不滅者核心</color>？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"확실히 발광하는 보석 형태의 아티팩트로군요. 그래서 이게 무슨 아티팩트입니까?","JPN":"確かに発光する宝石型のアーティファクトですね。それで、これは何のアーティファクトですか？","ENG":"It definitely fits the description... a gem-like Artifact that emits light on its own. So, what exactly is it?","TWN":"確實是發光的寶石形態的神器。那麼這是什麼神器呢？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"낸들 알아? 이게 뭔지가 중요한 게 아니라고!","JPN":"知らないわよ！　大事なのはこれが何かってことじゃない！","ENG":"How should I know?! What it is doesn't matter right now!","TWN":"我怎麼知道？這是什麼並不重要！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 정도 유도 파장이라면, 아티팩트가 있는 장소에는 침식체가 둥지를 틀고 있을 거야!","JPN":"これ程の誘導波長なら、アーティファクトがある場所には侵食体が巣食っているはず！","ENG":"With a lure wavelength this intense, there's no doubt the Artifact's location has become a nest for C.O.s!","TWN":"以這種程度的引導波長來看，有神器的地方一定有侵蝕體築巢！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"애초에 이곳에 4종 침식체가 나타난 이유가 이 불멸체 코어 때문일지도 모른다고!","JPN":"そもそもここに第4種侵食体が現れた理由が、この不滅体コアのせいだっていう可能性もある！","ENG":"The Category 4 C.O. might've shown up here in the first place because of this Immortal System Core!","TWN":"一開始這裡出現4類侵蝕體的原因，可能就是因為這個不滅者核心！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그 4종 침식체는 지금 대령님께서 맡아주고 계십니다.","JPN":"しかしその第4種侵食体は今、大佐が引き受けてくださっています。","ENG":"But right now, Colonel is keeping that Category 4 C.O. occupied.","TWN":"但是那4種侵蝕體現在由上校負責。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"우리에게 기회가 있다면, 그건 지금뿐이에요.","JPN":"我々にチャンスがあるとすれば、それは今しかありません。","ENG":"If we have a chance at all, it's right now!","TWN":"如果我們有機會，那就是現在。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"기회는 무슨 기회! 정신 차려, 카일!","JPN":"何がチャンスよ！　頭起きてる？　カイル！","ENG":"A chance?! Wake up, Kyle!","TWN":"什麼機會！清醒點，凱爾！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"고작 이 인원으로 아티팩트가 있는 곳까지 가봤자, 전멸이야! 개죽음이라고!","JPN":"たかがこの人数でアーティファクトのところまで行ったとしても、全滅するのがオチよ！　犬死になのよ！","ENG":"Charging in with these few people? We'll be slaughtered! It's a pointless death!","TWN":"就憑這點人手去有神器的地方，簡直是找死！全軍覆沒啊！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사람들을 다 죽일 셈이야? 이게 그렇게 중요한 거면 차라리 다음에…….","JPN":"全員殺す気？　これがそんなに大事なら、いっそのこと次の機会に……","ENG":"Are you planning to get everyone killed?! If this is so important, then we should wait for a better time...","TWN":"你打算把所有人都殺掉嗎？如果這件事真的那麼重要，不如下次再……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨야말로 정신 차리십시오!","JPN":"シルビアさんこそ、頭起きてるんですか？","ENG":"No, Sylvia, you're the one who needs to wake up!","TWN":"希爾維亞，你清醒一點！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신도 아시지 않습니까! 우리에게 다음 같은 건 없습니다!","JPN":"あなたにもわかるはずだ！　我々に次なんてものはもうない！","ENG":"You know as well as I do. We don't have a next time!","TWN":"你也知道的吧！我們沒有下一次了！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"며칠 전, 클리포트 게임의 여파로 저희 측은 대부분의 전력을 상실했습니다.","JPN":"数日前、クリフォトゲームでの戦闘により、我々は戦力の大半を失いました。","ENG":"A few days ago, we lost most of our forces in the aftermath of the Qliphoth Game.","TWN":"幾天前，由於逆卡巴拉遊戲的影響，我們這邊失去了大部分戰力。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사령관님께서는 의식 불명이고, 대령님께서도 큰 부상을 입었어요.","JPN":"司令官は意識不明の重体、大佐も重傷を負われました。","ENG":"The Commander is unconscious, and the Colonel is severely injured.","TWN":"司令官昏迷不醒，上校也受了重傷。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이런 상황에서 저희까지 실패한다면, 합중국… 아니, 인류에게 미래는 없습니다.","JPN":"このような状況で僕たちまで失敗したら、合衆国……いいえ、人類に未来はありません。","ENG":"If we fail here too... the States... no, humanity has no future.","TWN":"在這種情況下，如果我們也失敗了，合眾國……不，人類將沒有未來。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니까… 반드시 작전을 성공시켜야 해요.","JPN":"ですから……作戦は必ず成功させなければなりません。","ENG":"That's why... we have to succeed in this operation.","TWN":"所以……一定要成功完成任務。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"성공하면? 그 뒤에 우리에게 뭐가 있는데?","JPN":"成功したとして、その後には何があるってのよ？","ENG":"And if we do? Then what? What's waiting for us afterward?","TWN":"成功了又怎樣？接下來我們能得到什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"관리국도, 지휘부 꼰대들도 기밀이라면서 우리한테는 아무것도 알려주지 않았잖아!","JPN":"管理局も、司令部の年寄りどもも機密だとか言って、こっちには何も教えようとしなかったのよ！","ENG":"The Administration and the headquarters keep calling everything \\"classified\\" and leave us completely in the dark!","TWN":"管理局和指揮部的老頑固們都說是機密，什麼都沒告訴我們！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 게임의 끝에 뭐가 있지? 애초에 우리한테 승산이 있긴 해?","JPN":"このゲームの先に何があるって言うの？　そもそもアタシたちに勝算なんてあるの？","ENG":"What's even waiting at the end of this Game? Did we ever have a real chance to win?","TWN":"這戰役的盡頭是什麼？我們一開始真的就有勝算嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그게 아니면, 새로운 인류를 만들겠다는 그 헛소문을 진심으로 믿겠다는 거야?","JPN":"それとも、新人類を作るとか言うあのデマを真に受けてるの？","ENG":"Or are you seriously buying into that ridiculous rumor about creating a new human race?","TWN":"不然的話，你真要相信那個要創造新人類的荒謬傳聞嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"모르겠습니다.","JPN":"わかりません。","ENG":"I can't say for sure.","TWN":"我不知道。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 믿어야 한다면 믿겠습니다. 그게 군인이니까요.","JPN":"でも信じるしかないなら信じます。それが軍人ですから。","ENG":"But if I have to believe in it, I will. That's what it means to be a soldier.","TWN":"但是如果必須相信的話，我會相信的。這就是軍人。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야, 너 진짜……!!","JPN":"この、石頭……！！","ENG":"Hey, you seriously...!!","TWN":"喂，你真的……！！！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"소령님, 침식체 무리 다수가 그쪽으로 향하고 있습니다!","JPN":"少佐、多数の侵食体の群れがそちらに向かっています！","ENG":"Major! A large group of C.O.s is headed your way!","TWN":"少校，大量的侵蝕體群正朝那邊過去！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"목표 아티팩트의 위치는 특정되었습니까? 신속히 그곳에서 빠져나와야 합니다!","JPN":"アーティファクトの位置は特定できましたか？　速やかにそこから脱出してください！","ENG":"Have you located the target Artifact? You need to evacuate immediately!","TWN":"目標神器的位置確定了嗎？必須迅速從那裡撤離！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……알겠습니다. 즉시 이동하겠습니다.","JPN":"……了解しました。ただちに移動します。","ENG":"...Understood. I'm on the move.","TWN":"……明白，這就出發。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"쯧쯧! 거 봐, 내가 뭐랬어? 꽁냥거리는 건 둘만 있을 때나 하라고 했지?","JPN":"あーあ、だから言ったのに。イチャつくのは2人きりの時にしなって！","ENG":"Tsk tsk! Told you, didn't I? Save the couples' quarrel for when you're alone!","TWN":"嘖嘖！你看，我說什麼來著？不是說了只有兩個人的時候才能親熱嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"자, 싸울 준비나 하자고.","JPN":"ほら、戦う準備でもしとこうよ。","ENG":"Come on, weapons up.","TWN":"來吧，準備戰鬥吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"어차피 처음부터 우리에게 선택지 같은 건 없었잖아?","JPN":"どうせ最初からエイミーたちに選択肢なんかなかったわけだし？","ENG":"It's not like we ever had another option.","TWN":"反正從一開始我們就沒有選擇的餘地，不是嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};